/* Custom styles for the skin shop modal */
/* color variables and other themes are defined in In-Game Shop section */

a.btn:focus {
    box-shadow: none !important;
}

.modal-content-new {
    background-color: var(--modal-bg-color);
    border: 4px solid var(--modal-border-color);
    backdrop-filter: blur(10px);
    color: var(--modal-text-color);
    border-radius: 10px;
}

.modal-title {
    font-weight: 900;
    font-size: 1.75rem;
}

.modal-bg-color {
    background-color: #272e37e5;
}


.popover {
    background-color: #272e37e5;
    border: 2px solid #6b7280;
    color: white;
    border-radius: 10px;
}

.popover div{
    color:white;
}

.modal-header-new {
    border-bottom: 1px solid var(--modal-divider-color);
    padding : 16px;
    display: flex;
    flex-direction: "row";
    align-items: "center";
}

.modal-body-new {
    padding : 0px;
}

.owned-skins {
    border: 2px solid #6b7280;
    border-radius: 5px;
    padding: 5px;
    margin-bottom: 10px;
}

.owned-skins.active {
    background-color: #4b5563;
}

.other-lists {
    padding: 5px;
    color: var(--modal-text-color);
    border-radius: 5px;
}

.other-lists.active {
    background-color: var(--modal-tab-active-bg-color);
}

ul {
    list-style-type: none;
    margin: 0;
    padding: 0;
}

.modd-coin-bg {
    background-color: #374151;
}

.page-link {
    background-color: transparent !important;
    border: 0px solid #374151 !important;
    border-radius: 2px !important;
}

.page-item.active .page-link {
    background-color: transparent !important;
    border: 4px solid var(--purchasable-border-color) !important;
border-radius : 8px !important;
}

.blue-hover {
    margin: 5px;
    border: 2px solid transparent;
}

.blue-border {
    border: 2px solid #254edb;
    border-radius: 4px;
}

.blue-hover:hover {
    border: 2px solid #254edb;
    border-radius: 4px;
}

.blue-hover:hover .modd-coin-bg {
    background-color: #254edb;
}

.grey-bordered {
    border: 2px solid #374151;
    border-radius: 5px;
    box-sizing: border-box;
}

/* Default styles for larger screens */
.shop-grid-container {
  display: grid;
  background-color: var(--modal-content-bg-color);
  grid-template-columns: repeat(5, minmax(0, 1fr)); /* adjust column width as needed */
  grid-gap: 10px; /* adjust gap between grid items */
  max-width: 100%; /* ensure the grid container doesn't exceed the parent width */
  padding: 10px;
  border-radius: 10px;
}

.bottom-radius {
    border-radius: 0 0 8px 8px; /* Top-left, Top-right, Bottom-right, Bottom-left */
}

@media screen and (max-width: 767px) {
  .shop-grid-container {
    grid-template-columns: repeat(1, 1fr);
  }
}

@media screen and (min-width: 768px) and (max-width: 1023px) {
  .shop-grid-container {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media screen and (min-width: 1024px) and (max-width: 1279px) {
  .shop-grid-container {
    grid-template-columns: repeat(3, 1fr);
  }
}

@media screen and (min-width: 1279px) and (max-width: 2200px) {
  .shop-grid-container {
    grid-template-columns: repeat(4, 1fr);
  }
}


.shop-grid-items {
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    position: relative;
    cursor: pointer;
    justify-content: space-between !important;
    align-items: center;
    padding: 4px;
}

.skin-purchased {
    background-color: #955f3b !important;
    border: 6px solid var(--modal-border-color);
    border-radius: 10px !important;
}

.skin-unpurchased {
    background-color: #d5ad61 !important;
    border: 6px solid var(--modal-border-color);
    border-radius: 10px !important;
}

.justify-center {
    justify-content: center;
}

.justify-end {
    justify-content: end;
}

.unpurchasble-item{
    background-color: var(--unpurchasable-bg-color);
    border: 6px solid var(--purchasable-border-color);
    border-radius: 10px !important;
}

.unpurchasble-item:hover{
    background-color: var(--unpurchasable-bg-color-hover);
}

.skin-purchase-button {
    background-color: transparent;
    border: 2px solid var(--modal-border-color);
    color: var(--modal-border-color);
}

.skin-purchase-button:hover {
    background-color: #2f6a50;
    border: 2px solid #2f6a50;
    color: white;
}

.can-purchase-item {
    background-color: var(--purchasable-bg-color);
    color: var(--purchasable-text-color);
    border: 6px solid var(--purchasable-border-color);
    border-radius: 10px !important;
}

.lowered-visibility {
    opacity : 0.1;
}

.lowered-visibility {
    opacity : 0.3;
}

.can-purchase-item:hover{
    background-color: var(--purchasable-bg-color-hover);
    border: 6px solid var(--purchasable-border-color-hover);
    color: var(--purchasable-text-color-hover);
}

    .modd-shop-header {
        font-weight: 900;
        color: var(--modal-header-color);
        font-size : 1.5rem;
        -webkit-text-stroke : 1px var(--modal-header-border-color);
    }

    .modd-shop-sub-header {
        font-weight: 800;
        color: var(--modal-header-color);
        font-size : 1rem;
        margin-top: 10px;
        margin-left: 5px;
        -webkit-text-stroke : 1px  var(--modal-header-border-color);
    }

    #search-skin {
        color: var(--modal-text-color);
        placeholder: var(--modal-text-color);
        background-color: transparent;
        border: none;
        height: 28px;
    }

    .search-input-group {
        background-color: var(--modal-tab-active-bg-color);
        color: var(--modal-text-color);
        border: 2px solid var(--modal-coin-bg-color);
        display: flex;
        flex-direction: row;
        justify-content: center;
        align-items: center;
        padding: 6px;
        border-radius: 10px;
    }

.dark-bg, #chat-main-window > * > * {
    border: 4px solid #0000004D !important; 
    border-radius: 8px !important;
}

