leaderboardUI.cssData:
.progress-wrap .progress {
    height : 0rem !important;
}

#leaderboard {
    right: 0px;
    top: 30px;
    text-align: right;
    padding: 10px;

    position: absolute;
    color: white;
    /* display: none; */
    user-select: none;
}

.ui-text-scoreboard {
    font-size: 18px;
}

#scoreboard-header {
    border-bottom: 1px solid white;
    display: flex;
    align-items: center;
    gap: 2px;

    margin-bottom: 0px;
    width: fit-content;
    margin-left: auto;
}

#leaderboard-toggle {
    display: inline;
    cursor: pointer;
}

#leaderboard-title {
    cursor: pointer;
    text-decoration-line: none;
    font-size: 14px;
    font-weight: 600;
}

#scoreboard {
    height: 175px;
    overflow: auto;
    padding-top: 10px;
}

#scoreboard .scoreboard-mobile {
    width: 100px;
    height: 100px;
}

@media (min-width: 1024px) {
    .ui-text-scoreboard {
        font-size: 24px;
    }

    #scoreboard-header {
        gap: 4px;
    }

    #leaderboard-title {
        font-size: 18px;
        font-weight: 500;
    }
}

@media only screen and (max-width: 1000px) {
    #scoreboard .scoreboard-mobile {
        height: 100px;
        font-size: 13px;
    }
}
